import './index.css';

import {
  useEffect,
  useState
} from 'react';

import {
  getSubjects
} from '../../services/subjectService';

function StudentSubjects() {

  const [subjects, setSubjects] =
    useState([]);

  useEffect(() => {

    loadSubjects();

  }, []);

  const loadSubjects =
    async () => {

    try {

      const data =
        await getSubjects();

      setSubjects(data);

    } catch (error) {

      console.log(error);

    }

  };

  return (

    <div className="student-subjects">

      <h1>
        My Subjects
      </h1>

      <div className="subject-grid">

        {
          subjects.map((subject) => (

            <div
              key={subject.id}
              className="subject-card"
            >

              <h3>
                {subject.subject_name}
              </h3>

              <p>
                Semester:
                {' '}
                {subject.semester}
              </p>

            </div>

          ))
        }

      </div>

    </div>

  );

}

export default StudentSubjects;
